import abc

class Request:
    def __init__(self, method: str, url: str, headers: dict = None, body: str = None):
        self.method = method
        self.url = url
        self.headers = headers if headers is not None else {}
        self.body = body

    def __repr__(self):
        return f"Request(method='{self.method}', url='{self.url}', headers={self.headers}, body='{self.body}')"

class Response:
    def __init__(self, status_code: int, headers: dict = None, body: str = None):
        self.status_code = status_code
        self.headers = headers if headers is not None else {}
        self.body = body

    def __repr__(self):
        return f"Response(status_code={self.status_code}, headers={self.headers}, body='{self.body}')"

class Interceptor(abc.ABC):
    @abc.abstractmethod
    def pre_request(self, request: Request) -> Request:
        pass

    @abc.abstractmethod
    def post_request(self, request: Request, response: Response) -> Response:
        pass

class AuthInterceptor(Interceptor):
    def pre_request(self, request: Request) -> Request:
        if "Authorization" not in request.headers:
            request.headers["Authorization"] = "Bearer some_jwt_token"
        return request

    def post_request(self, request: Request, response: Response) -> Response:
        return response

class LoggerInterceptor(Interceptor):
    def pre_request(self, request: Request) -> Request:
        # Gerçek bir uygulamada, bu bir log dosyasına veya sistemine yazacaktır.
        return request

    def post_request(self, request: Request, response: Response) -> Response:
        # Gerçek bir uygulamada, bu bir log dosyasına veya sistemine yazacaktır.
        return response

class HeaderModifierInterceptor(Interceptor):
    def pre_request(self, request: Request) -> Request:
        if "Accept" not in request.headers:
            request.headers["Accept"] = "application/json"
        return request

    def post_request(self, request: Request, response: Response) -> Response:
        if "X-Correlation-ID" not in response.headers:
            response.headers["X-Correlation-ID"] = "generated-id"
        return response

class RequestDispatcher:
    def __init__(self):
        self._interceptors: list[Interceptor] = []

    def register_interceptor(self, interceptor: Interceptor):
        self._interceptors.append(interceptor)

    def _process_core_request(self, request: Request) -> Response:
        if request.url == "/api/data":
            if request.headers.get("Authorization") == "Bearer some_jwt_token":
                return Response(200, {"Content-Type": "application/json"}, '{"message": "Data retrieved"}')
            else:
                return Response(401, {}, '{"message": "Unauthorized"}')
        elif request.url == "/api/status":
            return Response(200, {"Content-Type": "text/plain"}, "Service is up")
        else:
            return Response(404, {}, '{"message": "Not Found"}')

    def dispatch(self, request: Request) -> Response:
        current_request = request
        for interceptor in self._interceptors:
            current_request = interceptor.pre_request(current_request)

        response = self._process_core_request(current_request)

        current_response = response
        for interceptor in reversed(self._interceptors):
            current_response = interceptor.post_request(current_request, current_response)

        return current_response
